#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=1e5+5;
int n,a[MAXN],c;
bool f(int x){
	int s=a[1],ans=0;
	for(int i=2;i<=n;i++){
		if(a[i]-s<x)ans++;
		else s=a[i];
		if(ans>n-c)return false;
	} return true;
} 
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d",&n,&c);
	for(int i=1;i<=n;i++)scanf("%d",a+i);
	sort(a+1,a+n+1);
	int l=1,r=a[n]-a[1];
	while(l+1<r){
		int mid=(l+r)/2;
		if(f(mid))l=mid;
		else r=mid;
	}printf("%d",l);
	return false;
}
